import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "What is the standard rise and run for stairs?", a: "The standard rise (vertical height per step) is 7-7.75 inches, and the standard run (horizontal tread depth) is 10-11 inches. IRC building code requires: minimum run of 10 inches, maximum rise of 7.75 inches, and a minimum stair width of 36 inches. Consistent rise-run throughout a staircase is critical for safety." },
  { q: "How many stairs do I need for a 9-foot ceiling?", a: "A 9-foot ceiling (108 inches) with a standard 7-inch rise needs approximately 15-16 steps (108  x  7 = 15.43, so 16 steps with an actual riser of 6.75 inches each). Use this calculator with your exact ceiling height to get the precise number and adjusted riser height." },
  { q: "What is the formula for stair calculations?", a: "Number of steps = ceil(Total Rise / Desired Riser Height). Actual Riser = Total Rise / Number of Steps. Total Run = Number of Steps x Tread Depth. Stringer Length = square root of Rise squared plus Total Run squared. The 2R + T rule is a traditional comfort check." },
  { q: "What is the ideal stair angle?", a: "The ideal residential stair angle is about 30 to 37 degrees. Below 25 degrees stairs feel too shallow and take up too much horizontal space. Above 45 degrees stairs feel like a ladder. The standard 7/11 rise/run combination produces about a 32.5 degree angle." },
  { q: "What is a stringer and how long should it be?", a: "A stringer is the angled structural board that supports the treads and risers. Stringer length is calculated with the Pythagorean theorem using total rise and total run. Use 2x lumber, typically 2x12, for residential stringers." },
  { q: "How do I calculate material for stair treads?", a: "Number of treads = Number of steps (the top landing is the floor, not a tread). Tread material = (Tread Depth + Nosing Overhang)  x  Stair Width  x  Number of Treads. Standard nosing overhang: 0.75-1.25 inches. Multiply by the number of stairs and add 10% waste. Common tread: 1-inch  x  10-inch  x  stair width lumber." },
  { q: "What is the 2R+T rule for stairs?", a: "The 2R+T formula (twice the riser plus the tread) should equal 24-25 inches for comfortable stairs. Example: 7-inch rise and 11-inch tread: 2 x 7 + 11 = 25 - perfect. If 2R+T is too low (<24), the stairs feel too shallow and awkward. Too high (>26) and they feel steep and tiring." },
  { q: "Do outdoor stairs need to meet building code?", a: "Yes - all exterior stairs attached to a house (decks, porches, entrances) must meet local building code which typically mirrors IRC standards: max 7.75-inch rise, min 10-inch run, min 36-inch width, handrail required for 4+ risers, and graspable handrail profile. Permits are required in most jurisdictions for attached deck stairs." },
];

const RISE_REFERENCE = [
  ["7 ft (84\")", "84", "12 steps", "7.0\" riser", "132\" (11 ft)"],
  ["8 ft (96\")", "96", "14 steps", "6.86\" riser", "154\" (12.8 ft)"],
  ["9 ft (108\")", "108", "16 steps", "6.75\" riser", "176\" (14.7 ft)"],
  ["10 ft (120\")", "120", "17 steps", "7.06\" riser", "187\" (15.6 ft)"],
  ["11 ft (132\")", "132", "19 steps", "6.95\" riser", "209\" (17.4 ft)"],
  ["12 ft (144\")", "144", "21 steps", "6.86\" riser", "231\" (19.3 ft)"],
];

export default function StairCalculator() {
  const [totalRise, setTotalRise] = useState(108);
  const [riserHeight, setRiserHeight] = useState(7);
  const [treadDepth, setTreadDepth] = useState(11);
  const [stairWidth, setStairWidth] = useState(36);

  const numSteps = Math.ceil(totalRise / riserHeight);
  const actualRiser = totalRise / numSteps;
  const totalRun = numSteps * treadDepth;
  const stairAngle = Math.atan(actualRiser / treadDepth) * (180 / Math.PI);
  const stringerLength = Math.sqrt(totalRun * totalRun + totalRise * totalRise) / 12;
  const comfort2RT = (2 * actualRiser + treadDepth).toFixed(1);
  const isComfort = parseFloat(comfort2RT) >= 24 && parseFloat(comfort2RT) <= 25;

  return (
    <>
      <SEOHead
        title="Free Stair Calculator Online - Calculate Steps Riser Height and Stringer Length Instantly | CalcHive"
        description="Free online stair calculator. Calculate number of steps, riser height, total run and stringer length for any staircase instantly. 100% free for builders and DIY projects, no signup required."
        canonical="/stair-calculator"
        keywords="free stair calculator, staircase calculator online free, calculate stair riser height free, stringer length calculator free, steps calculator for stairs free"
        category="Construction Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-stone-600 dark:text-stone-400 bg-stone-100 dark:bg-stone-800/50 px-3 py-1 rounded-full mb-4 inline-block">Housing</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Stair Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free stair calculator to calculate stair riser height free, number of steps, total run, and stringer length. This staircase calculator online free also works as a stringer length calculator free and steps calculator for stairs free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="total-rise" label="Total Rise (inches)" value={totalRise} min={36} max={300} step={1} onChange={setTotalRise} format={v => `${v}" (${(v/12).toFixed(2)} ft)`} testId="input-total-rise" helpText="Floor-to-floor vertical height" />
            <SliderInput id="riser" label="Desired Riser Height (inches)" value={riserHeight} min={4} max={8} step={0.25} onChange={setRiserHeight} format={v => `${v}"`} testId="input-riser" helpText={'IRC code max: 7.75" - Standard: 7"'} />
            <SliderInput id="tread" label="Tread Depth (inches)" value={treadDepth} min={8} max={16} step={0.5} onChange={setTreadDepth} format={v => `${v}"`} testId="input-tread" helpText={'IRC code min: 10" - Standard: 11"'} />
            <SliderInput id="width" label="Stair Width (inches)" value={stairWidth} min={24} max={96} step={1} onChange={setStairWidth} format={v => `${v}"`} testId="input-width" helpText={'IRC code min: 36"'} />
          </div>
          <motion.div key={`${totalRise}-${riserHeight}-${treadDepth}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-stone-600 to-stone-800 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Number of Steps</p>
              <p className="text-7xl font-black text-white tracking-tight" data-testid="result-steps">{numSteps}</p>
              <p className="text-white/70 text-sm mt-1">steps - {stairAngle.toFixed(1)} degree angle</p>
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 mb-3">
              {[
                { label: "Actual Riser", value: `${actualRiser.toFixed(2)}"` },
                { label: "Total Run", value: `${totalRun}" (${(totalRun/12).toFixed(1)} ft)` },
                { label: "Stair Angle", value: `${stairAngle.toFixed(1)} deg` },
                { label: "Stringer Length", value: `${stringerLength.toFixed(2)} ft` },
              ].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-sm font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
            <div className={`text-xs text-center px-4 py-2 rounded-lg ${isComfort ? "bg-green-50 dark:bg-green-950/30 text-green-600 dark:text-green-400" : "bg-amber-50 dark:bg-amber-950/30 text-amber-600 dark:text-amber-400"}`}>
              2R+T comfort check: {comfort2RT}" {isComfort ? "(excellent - 24-25\" range)" : "(outside ideal 24-25\" range)"}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Stair Steps and Riser Height for Free</h2>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Steps = ceil(Total Rise  x  Desired Riser)</p>
            <p>Actual Riser = Total Rise  x  Steps</p>
            <p>Total Run = Steps  x  Tread Depth</p>
            <p>Stringer = square root of Rise squared + Total Run squared</p>
            <p>Stair Angle = arctan(Riser  x  Tread) in degrees</p>
            <p className="text-xs text-muted-foreground mt-2">Comfort rule: 2  x  Riser + Tread = 24-25 inches</p>
            <p className="text-xs text-muted-foreground">IRC code: max riser 7.75", min tread 10", min width 36"</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Find Total Run and Stringer Length for Any Staircase</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Floor Height", "Rise (in)", "Steps (7\" target)", "Actual Riser", "Total Run (11\" tread)"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {RISE_REFERENCE.map(([height, rise, steps, riser, run]) => (
                  <tr key={height} className={`hover:bg-muted/30 ${parseInt(rise) === totalRise ? "bg-stone-50 dark:bg-stone-800/30 font-semibold" : ""}`}>
                    <td className="py-2.5 px-4 font-bold text-stone-600 dark:text-stone-400">{height}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{rise}"</td>
                    <td className="py-2.5 px-4 text-foreground">{steps}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{riser}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{run}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Staircase Calculator for Builders and DIY Projects</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free construction tool on mobile or desktop to estimate materials quickly, compare project scenarios, and plan with less guesswork.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/stair-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


